func TestReport_OutcomeReason_Persists_BesideDisrupted(t *testing.T) {
	report := ExecuteBeadReport{
		BeadID:                      "ddx-test",
		Status:                      ExecuteBeadStatusNoChanges,
		Disrupted:                   true,
		DisruptionReason:            "transport_error",
		OutcomeReason:               "transport",
