120	type SatisfactionChecker interface {
121		CheckSatisfied(ctx context.Context, beadID string, noChangesCount int) (bool, string, error)
122	}
123	
124	type NoChangesOutcome struct {
125		Satisfied bool
126		Evidence  string
127		EventKind string
128		EventBody string
129		Label     string
130	}
131	
132	func adjudicateNoChangesContract(ctx context.Context, beadID string, report Report, projectRoot string, noChangesCount int, checker SatisfactionChecker, runner VerificationCommandRunner) (NoChangesOutcome, Report, error) {
133		if checker != nil {
134			satisfied, evidence, err := checker.CheckSatisfied(ctx, beadID, noChangesCount)
135			if err != nil {
136				return NoChangesOutcome{}, report, err
137			}
138			if satisfied {
139				if evidence != "" {
140					report.Detail = evidence
141				}
142				report.Status = StatusAlreadySatisfied
143				return NoChangesOutcome{Satisfied: true, Evidence: evidence}, report, nil
144			}
145			return NoChangesOutcome{Satisfied: false}, report, nil
146		}
147	
148		parsed := ParseNoChangesRationale(report.NoChangesRationale)
149		switch parsed.Kind {
150		case NoChangesKindVerified:
151			if runner == nil {
152				runner = DefaultVerificationCommandRunner
153			}
154			exitCode, output, runErr := runner(ctx, projectRoot, parsed.VerificationCommand)
155			body := fmt.Sprintf("verification_command=%s\nexit_code=%d", parsed.VerificationCommand, exitCode)
156			if output != "" {
157				body += "\noutput:\n" + output
158			}
159			if runErr != nil {
160				body += "\nrun_error: " + runErr.Error()
161			}
162			if runErr == nil && exitCode == 0 {
163				evidence := fmt.Sprintf("verification_command passed: %s", parsed.VerificationCommand)
164				report.Detail = evidence
165				report.Status = StatusAlreadySatisfied
166				return NoChangesOutcome{
167					Satisfied: true,
168					Evidence:  evidence,
169					EventKind: NoChangesEventVerified,
170					EventBody: body,
171				}, report, nil
172			}
173			return NoChangesOutcome{
174				Satisfied: false,
175				EventKind: NoChangesEventUnverified,
176				EventBody: body,
177				Label:     NoChangesLabelUnverified,
178			}, report, nil
179		case NoChangesKindNeedsInvestigation:
180			body := parsed.NeedsInvestigationReason
181			if body == "" {
182				body = "(no reason provided)"
183			}
184			return NoChangesOutcome{
185				Satisfied: false,
186				EventKind: NoChangesEventNeedsInvestigation,
187				EventBody: body,
188				Label:     NoChangesLabelNeedsInvestigation,
189			}, report, nil
190		default:
191			body := strings.TrimSpace(report.NoChangesRationale)
192			if body == "" {
193				body = "(rationale absent)"
194			}
195			return NoChangesOutcome{
196				Satisfied: false,
197				EventKind: NoChangesEventUnjustified,
198				EventBody: body,
199				Label:     NoChangesLabelUnjustified,
200			}, report, nil
201		}
202	}

